def reverse_string(s: str) -> str:
    if not isinstance(s, str):
        raise TypeError("Input must be a string")
    return s[::-1]

if __name__ == "__main__":
    import sys
    if len(sys.argv) > 1:
        print(reverse_string(sys.argv[1]))
    else:
        print(reverse_string(sys.stdin.read().rstrip("\n")))
EOF
) && echo 'print("OK")' >/dev/null; elif grep -qi "fizzbuzz" task.txt; then echo "Detected fizzbuzz task; implementing"; ( [ -f fizzbuzz.py ] || cat <<'EOF' > fizzbuzz.py
def fizzbuzz(n: int):
    if not isinstance(n, int):
        raise TypeError("n must be int")
    if n < 1:
        return []
    res = []
    for i in range(1, n+1):
        out = ""
        if i % 3 == 0:
            out += "Fizz"
        if i % 5 == 0:
            out += "Buzz"
        res.append(out or str(i))
    return res

if __name__ == "__main__":
    import sys, json
    n = int(sys.argv[1]) if len(sys.argv) > 1 else 100
    print("\n".join(fizzbuzz(n)))
EOF
); elif grep -qi "bug" task.txt || grep -qi "fix" task.txt; then echo "Searching for failing tests to fix"; (python3 -m pytest -q || true); else echo "No heuristic recognized; printing task.txt for manual review"; fi; fi && echo "----- Re-run tests after potential changes -----" && ( [ -f pyproject.toml ] && (python3 -m pytest -q || true) || true ) && echo "----- Create a small verification script if reverse_string was created -----" && if [ -f main.py ]; then python3 - <<'PY'
